struct GoogleMapView: UIViewRepresentable {
    @Binding var selectedLocation: CLLocationCoordinate2D

    func makeCoordinator() -> Coordinator {
        Coordinator(selectedLocation: $selectedLocation)
    }

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(
            withLatitude: selectedLocation.latitude,
            longitude: selectedLocation.longitude,
            zoom: 12
        )
        let mapView = GMSMapView.map(withFrame: .zero, camera: camera)
        mapView.delegate = context.coordinator
        mapView.settings.myLocationButton = false
        mapView.settings.zoomGestures = true

        let marker = GMSMarker(position: selectedLocation)
        marker.title = "Demo Pin"
        marker.snippet = "Tap to move"
        marker.map = mapView

        context.coordinator.marker = marker
        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {
        uiView.camera = GMSCameraPosition.camera(
            withLatitude: selectedLocation.latitude,
            longitude: selectedLocation.longitude,
            zoom: uiView.camera.zoom
        )
        context.coordinator.marker?.position = selectedLocation
    }

    final class Coordinator: NSObject, GMSMapViewDelegate {
        @Binding var selectedLocation: CLLocationCoordinate2D
        var marker: GMSMarker?

        init(selectedLocation: Binding<CLLocationCoordinate2D>) {
            _selectedLocation = selectedLocation
        }

        func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
            selectedLocation = coordinate
            marker?.position = coordinate
        }
    }
}

struct PaymentDemoView: View {
    @Binding var paymentStatus: String
    @Environment(\.dismiss) private var dismiss
    @State private var isProcessing = false

    var body: some View {
        NavigationView {
